public class JITExample {
    public static void main(String[] args) {
        long start = System.nanoTime();
        for (int i = 0; i < 10_000_000; i++) {
            compute();
        }
        long end = System.nanoTime();
        System.out.println("Execution Time: " 
        	+ (end - start) + " ns");
    }

    static void compute() {
        int x = 5 * 10;
    }
}

