class ComplexClass {
    private Sortable sorter;

    ComplexClass(Sortable sorter) {
        this.sorter = sorter;
    }

    void doAComplexThing() {
        int[] values = null;

        // logic...

        sorter.sort(values);

        // logic...
    }
}

