import java.util.concurrent.Semaphore;

class Worker implements Runnable {

    private Semaphore semaphore;

    Worker(Semaphore semaphore) {
        this.semaphore = semaphore;
    }

    public void run() {
        try {

            semaphore.acquire(); // Acquire permit

            System.out.println(
                Thread.currentThread().getName() + 
                " working...");

            Thread.sleep(1000);

            semaphore.release(); // Release permit

        } catch (InterruptedException e) { 
            e.printStackTrace();
        }
    }
}

public class Main {
    public static void main(String[] args) {
        // Max 2 threads at a time
        Semaphore semaphore = new Semaphore(2); 

        new Thread(new Worker(semaphore)).start();
        new Thread(new Worker(semaphore)).start();
        new Thread(new Worker(semaphore)).start();
    }
}

import java.util.concurrent.CountDownLatch;

class Worker implements Runnable {

    private CountDownLatch latch;

    Worker(CountDownLatch latch) {
        this.latch = latch;
    }

    public void run() {
        System.out.println(
            Thread.currentThread().getName() + 
            " finished work.");
        latch.countDown(); // Reduce the latch count
    }
}

public class Main {
    public static void main(String[] args) 
                    throws InterruptedException {

        CountDownLatch latch = new CountDownLatch(2);

        for (int i = 0; i < 10; i++) {
            Thread t = new Thread(new Worker(latch));
            t.start();
        }

        latch.await(); 

        System.out.println(
            "At least 2 workers finished execution.");
    }
}

class Calculator extends Thread {
    long sumUptoMillion;

    public void run() {
        synchronized (this) { // Locking on this object
            calculateSumUptoMillion();
            notify(); // Notify waiting thread
        }
    }

    private void calculateSumUptoMillion() {
        for (int i = 0; i < 1000000; i++) {
            sumUptoMillion += i;
        }
    }
}

public class ThreadWaitNotify {
    public static void main(String[] args) 
                    throws InterruptedException {

        Calculator thread = new Calculator();

        synchronized (thread) { // Locking on the same object
            thread.start(); // Start calculation thread
            thread.wait();  // Wait for notification
        }

        System.out.println("Sum up to million: " 
                                + thread.sumUptoMillion);
    }
}

class Resource {

    private final String name;

    public Resource(String name) {
        this.name = name;
    }

    void use(Resource other) {

        // Locking this resource first
        synchronized (this) {

            System.out.println(
                Thread.currentThread().getName() 
                + " locked " + this.name);

            try { 
                Thread.sleep(100); 
            } catch (InterruptedException e) {
                e.printStackTrace();
            }

            // Now locking the second resource
            synchronized (other) { 
                System.out.println(
                    Thread.currentThread().getName() 
                    + " locked " + other.name);
            }
        }

    }
}

public class DeadlockExample {

    public static void main(String[] args) {

        Resource resourceA 
                = new Resource("Resource A");

        Resource resourceB 
                = new Resource("Resource B");

        // Thread-1 locks A → B
        Thread t1 = new Thread(() 
                            -> resourceA.use(resourceB), 
                                            "Thread-1");

        // Thread-2 locks B → A (Deadlock risk!) 
        Thread t2 = new Thread(() 
                        -> resourceB.use(resourceA), 
                                            "Thread-2");

        t1.start();
        t2.start();
    }
}

class Resource {
    private final String name;

    public Resource(String name) {
        this.name = name;
    }

    void use(Resource other) {

        Resource first = this.name
                            .compareTo(other.name) < 0 
                            ? this : other;

        Resource second = this.name
                              .compareTo(other.name) < 0 
                              ? other : this;

        // Always lock lower-named resource first
        synchronized (first) { 
            System.out.println(
                Thread.currentThread().getName() 
                + " locked " + first.name);

            try { 
                Thread.sleep(100); 
            } catch (InterruptedException e) {
                e.printStackTrace();
            }

            synchronized (second) { // Lock 2nd resource
                System.out.println(
                    Thread.currentThread().getName() 
                    + " locked " + second.name);
            }
        }
    }
}

public class DeadlockSolution {
    public static void main(String[] args) {
        Resource resourceA = new Resource("Resource A");
        Resource resourceB = new Resource("Resource B");

        // Both threads now lock in the same order: A → B
        Thread t1 = new Thread(
                        () -> resourceA.use(resourceB), 
                        "Thread-1");

        Thread t2 = new Thread(
                        () -> resourceB.use(resourceA), 
                        "Thread-2");

        t1.start();
        t2.start();
    }
}

