public class FailFast {
    public static void main(String[] args) {

        Map<String, String> map = new HashMap<>();

        map.put("key1", "value1");
        map.put("key2", "value2");
        map.put("key3", "value3");

        Iterator<String> iterator = map.keySet().iterator();

        while (iterator.hasNext()) {

