class Task<I, R> {
    private I input;
    private R result;

    public Task(I input, R result) {
        this.input = input;
        this.result = result;
    }


    public R process() {
        System.out.println("Processing input: " + input);

        if (result != null) {
            System.out.println("Returning result: " + result);
        } else {
            System.out.println("Returning no result (Void)");
        }

        return result;
    }
}

